diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 6e4689863407..5d9703e1cc66 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1330,14 +1330,18 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
   // Look through add of a constant offset on V1, V2, or both operands. This
   // allows us to interpret the V + C' < C'' range idiom into a proper range.
   const APInt *Offset1 = nullptr, *Offset2 = nullptr;
+  const APInt *Mask1 = nullptr, *Mask2 = nullptr;
   if (V1 != V2) {
     Value *X;
     if (match(V1, m_Add(m_Value(X), m_APInt(Offset1))))
       V1 = X;
+    else if (match(V1, m_And(m_Value(X), m_APInt(Mask1))))
+      V1 = X;
     if (match(V2, m_Add(m_Value(X), m_APInt(Offset2))))
       V2 = X;
+    else if (match(V2, m_And(m_Value(X), m_APInt(Mask2))))
+      V2 = X;
   }
-
   if (V1 != V2)
     return nullptr;

@@ -1345,6 +1349,13 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
       IsAnd ? ICmpInst::getInverseCmpPredicate(Pred1) : Pred1, *C1);
   if (Offset1)
     CR1 = CR1.subtract(*Offset1);
+  else if (Mask1) {
+    if (CR1.isSingleElement()) {
+      // not yet implemented, just fallback
+    } else {
+      // not implemented
+    }
+  }

   ConstantRange CR2 = ConstantRange::makeExactICmpRegion(
       IsAnd ? ICmpInst::getInverseCmpPredicate(Pred2) : Pred2, *C2);
@@ -3327,6 +3338,50 @@ static Value *foldAndOrOfICmpEqConstantAndICmp(ICmpInst *LHS, ICmpInst *RHS,
       Builder.CreateSub(LHS0, ConstantInt::get(LHS0->getType(), *CInt + 1)),
       Other);
 }
+static Value *foldAndOrOfICmpEqAndMaskedICmp(ICmpInst *LHS, ICmpInst *RHS,
+                                             bool IsAnd, IRBuilderBase &Builder) {
+  Value *X;
+  const APInt *C1, *C2, *Mask;
+
+  ICmpInst::Predicate LPred = IsAnd ? LHS->getInversePredicate() : LHS->getPredicate();
+  ICmpInst::Predicate RPred = IsAnd ? RHS->getInversePredicate() : RHS->getPredicate();
+
+  if (LPred != ICmpInst::ICMP_EQ || RPred != ICmpInst::ICMP_EQ)
+    return nullptr;
+
+  if (!match(LHS->getOperand(0), m_Value(X)) ||
+      !match(LHS->getOperand(1), m_APInt(C1)) ||
+      !match(RHS->getOperand(0), m_And(m_Specific(X), m_APInt(Mask))) ||
+      !match(RHS->getOperand(1), m_APInt(C2)))
+    return nullptr;
+
+  if (Mask->isZero() || C2->isZero()) // removed C1->isZero() check, since (X == 0) | ((X & M) == C2) could be valid. But wait, if C1=0, C2=1, mask=-2. (X == 0) | (X & -2 == 1) -> (X == 0) | false, C2 must be a multiple of the bit step!
+    return nullptr;
+
+  APInt NotMask = ~*Mask;
+  if (!NotMask.isMask())
+    return nullptr;
+
+  APInt Lower = *C2;
+  APInt Upper = Lower + NotMask + 1;
+
+  APInt Diff;
+  APInt CmpVal;
+  if (*C1 == Lower - 1) {
+    Diff = *C1;
+    CmpVal = NotMask + 2;
+  } else if (*C1 == Upper) {
+    Diff = Lower;
+    CmpVal = NotMask + 2;
+  } else {
+    return nullptr;
+  }
+
+  Value *Sub = Builder.CreateSub(X, ConstantInt::get(X->getType(), Diff));
+  return Builder.CreateICmp(IsAnd ? ICmpInst::ICMP_UGE : ICmpInst::ICMP_ULT,
+                            Sub, ConstantInt::get(X->getType(), CmpVal));
+}
+// removed

 /// Fold (icmp)&(icmp) or (icmp)|(icmp) if possible.
 /// If IsLogical is true, then the and/or is in select form and the transform
@@ -3367,7 +3422,10 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
   if (Value *V = foldAndOrOfICmpEqConstantAndICmp(RHS, LHS, IsAnd,
                                                   /*IsLogical*/ false, Builder))
     return V;
-
+  if (Value *V = foldAndOrOfICmpEqAndMaskedICmp(LHS, RHS, IsAnd, Builder))
+    return V;
+  if (Value *V = foldAndOrOfICmpEqAndMaskedICmp(RHS, LHS, IsAnd, Builder))
+    return V;
   if (Value *V =
           foldAndOrOfICmpsWithConstEq(LHS, RHS, IsAnd, IsLogical, Builder, Q))
     return V;
@@ -3449,10 +3507,14 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
             foldAndOrOfICmpsWithPow2AndWithZero(Builder, LHS, RHS, IsAnd, Q))
       return V;

-  // This only handles icmp of constants: (icmp1 A, C1) | (icmp2 B, C2).
   if (!LHSC || !RHSC)
     return nullptr;

+  if (Value *V = foldAndOrOfICmpsWithConstEq(LHS, RHS, IsAnd, IsLogical, Builder, Q))
+    return V;
+  if (Value *V = foldAndOrOfICmpsWithConstEq(RHS, LHS, IsAnd, IsLogical, Builder, Q))
+    return V;
+
   // (trunc x) == C1 & (and x, CA) == C2 -> (and x, CA|CMAX) == C1|C2
   // (trunc x) != C1 | (and x, CA) != C2 -> (and x, CA|CMAX) != C1|C2
   // where CMAX is the all ones value for the truncated type,

